var input = $json;

const novoDialogo = {
  createdAt : DateTime.now(),
  usuario: input.msg.incomingMessage,
  agente: input.respostaIA.userMessage
};


let actionDataContext = $json.pessoa.contexto_memoria.actionDataContext;
let newActionDataContext = $json.respostaIA.actionDataContext;
newActionDataContext.faseCore = input.respostaIA.nextState;

/**
if (newActionDataContext._RESET_CONTEXT) {
  newActionDataContext = {faseCore : newActionDataContext.faseCore};
} else {
  newActionDataContext = {...actionDataContext, ...newActionDataContext };  
}
*/


input.pessoa.contexto_memoria.conversas_recentes.push(novoDialogo);
input.pessoa.contexto_memoria.actionDataContext = {...newActionDataContext, ...actionDataContext};


return $input.item;

const pessoa = $json.pessoa;

const newADC = $json.respostaIA.actionDataContext;

if (newADC._RESET_CONTEXT) {
  pessoa.contexto_memoria.actionDataContext = {};
} else {
  const adc = pessoa.contexto_memoria.actionDataContext;
  pessoa.contexto_memoria.actionDataContext = {...adc, ...newADC};

  $input.item.json.pessoa = pessoa;
}




return $input.item;

const ad = $json.respostaIA?.actionData;
if (!ad) return $input.item;

const alias = {
  os_id:                  ['id_os', 'ordem_servico_id', 'os_selecionada', 'os_id_selecionada'],
  data_hora_agendamento:  ['agendado_para', 'data_agendamento', 'data_hora', 'horario', 'data_confirmada', 'data_hora_confirmada', 'horario_agendamento'],
  placa_veiculo:          ['placa', 'placa_carro', 'placa_do_veiculo'],
  modelo_veiculo:         ['modelo', 'modelo_carro', 'modelo_do_veiculo'],
  marca_veiculo:          ['marca', 'marca_carro', 'marca_do_veiculo'],
  descricao_problema:     ['problema', 'sintoma', 'descricao', 'relato', 'descricao_sintoma'],
  nome_cliente:           ['nome', 'cliente', 'nome_do_cliente'],
  telefone_cliente:       ['telefone', 'whatsapp', 'phone', 'celular', 'contato'],
  descricao_progresso:    ['progresso', 'atualizacao', 'update', 'descricao_atualizacao'],
  observacoes_recepcao:   ['observacao', 'nota', 'anotacao', 'observacao_recepcao'],
  notificacao_consultor:  ['notificacao', 'mensagem_consultor', 'msg_consultor'],
  evento_os:              ['evento', 'log', 'registro', 'log_evento']
};

for (const [canonical, variants] of Object.entries(alias)) {
  if (!(canonical in ad)) {
    for (const v of variants) {
      if (v in ad) {
        ad[canonical] = ad[v];
        delete ad[v];
        break;
      }
    }
  }
}

$input.item.json.respostaIA.actionData = ad;
return $input.item;
